function formatDate(dateStr) {
  if (!dateStr) return '';
  var d = new Date(dateStr);
  return d.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
window.openNotes = function () {
  appsmith.triggerEvent('onOpenNotes');
};
appsmith.onReady(function () {
  appsmith.triggerEvent('onPageLoad');
});
function render(m) {
  var customerName = document.getElementById('customer-name');
  var collectionId = document.getElementById('collection-id');
  var collectionDate = document.getElementById('collection-date');
  var status = document.getElementById('status');
  var jobType = document.getElementById('job-type');
  var address = document.getElementById('address');
  var notesCount = document.getElementById('notes-count');
  if (customerName) customerName.textContent = m.customerName || 'Loading...';
  if (collectionId) collectionId.textContent = m.collectionId ? 'Collection #' + m.collectionId : '';
  if (collectionDate) collectionDate.textContent = formatDate(m.collectionDate);
  if (status) status.textContent = m.status || '';
  if (jobType) jobType.textContent = m.jobType || '';
  if (address) address.textContent = m.address || '';
  if (notesCount) notesCount.textContent = m.notesCount !== undefined ? m.notesCount : 0;
}
appsmith.triggerEvent("onPageLoad");
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (m) {
  render(m);
});

